 1	import React, { ReactNode } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import Loading from '@kubevirt-utils/components/Loading/Loading';
 5	import { Alert, AlertGroup, AlertVariant } from '@patternfly/react-core';
 6	
 7	import { injectDisabled } from '../utils/utils';
 8	
 9	import UploadErrorMessage from './UploadPVCErrorMessage';
10	
11	type UploadPVCButtonBarProps = {
12	  children?: ReactNode;
13	  className?: string;
14	  errorMessage?: string;
15	  infoMessage?: string;
16	  inProgress?: boolean;
17	  successMessage?: string;
18	  uploadProxyURL?: string;
19	};
20	
21	const UploadPVCButtonBar: React.FC<UploadPVCButtonBarProps> = ({
22	  children,
23	  className,
24	  errorMessage,
25	  infoMessage,
26	  inProgress,
27	  successMessage,
28	  uploadProxyURL,
29	}) => {
30	  return (
31	    <div className={classNames(className, 'co-m-btn-bar')}>
32	      <AlertGroup
33	        aria-atomic="false"
34	        aria-live="polite"
35	        aria-relevant="additions text"
36	        isLiveRegion
37	      >
38	        {successMessage && (
39	          <Alert
40	            className="co-alert"
41	            isInline
42	            title={successMessage}
43	            variant={AlertVariant.success}
44	          />
45	        )}
46	        {errorMessage && (
47	          <UploadErrorMessage message={errorMessage} uploadProxyURL={uploadProxyURL} />
48	        )}
49	        {injectDisabled(children, inProgress)}
50	        {inProgress && <Loading />}
51	        {infoMessage && (
52	          <Alert className="co-alert" isInline title={infoMessage} variant={AlertVariant.info} />
53	        )}
54	      </AlertGroup>
55	    </div>
56	  );
57	};
58	
59	export default UploadPVCButtonBar;

